INSERT INTO grammar_lessons (id,title_mn,title_zh,grammar_point,explanation_mn,pattern,examples,hsk_level,order_num,is_published) VALUES
(26,'Энэ/тэр (这/那)','这/那','这/那','「这」= энэ, 「那」= тэр (заах үг).','这/那 + 是 + N','[{"zh": "这是我的书。", "pinyin": "Zhè shì wǒ de shū.", "mn": "Энэ миний ном."}, {"zh": "那是学校。", "pinyin": "Nà shì xuéxiào.", "mn": "Тэр сургууль."}]',1,26,1),
(27,'Хэд вэ? (几)','几 how many','几','Тоо асуухдаа 「几」 ашиглана.','几 + MW + N?','[{"zh": "你有几个苹果？", "pinyin": "Nǐ yǒu jǐ gè píngguǒ?", "mn": "Чи хэдэн алимтай вэ?"}, {"zh": "现在几点？", "pinyin": "Xiànzài jǐ diǎn?", "mn": "Одоо хэдэн цаг вэ?"}]',1,27,1),
(28,'吧 зөөлөн санал','吧 suggestion','吧','Төгсгөлд 「吧」 нэмвэл зөөлөн санал болно.','…吧。','[{"zh": "我们走吧。", "pinyin": "Wǒmen zǒu ba.", "mn": "Явцгаая."}, {"zh": "你坐吧。", "pinyin": "Nǐ zuò ba.", "mn": "Суугаарай."}]',1,28,1),
(29,'Холбоос (和)','和 and','和','「和」 хоёр зүйлийг холбоно.','A + 和 + B','[{"zh": "我和妈妈在家。", "pinyin": "Wǒ hé māma zài jiā.", "mn": "Би ээжтэйгээ гэртээ."}, {"zh": "茶和咖啡", "pinyin": "chá hé kāfēi", "mn": "цай ба кофе"}]',1,29,1),
(30,'Эелдэг асуух (请问)','请问 polite ask','请问','Асуулт эхлүүлэх эелдэг хэлбэр.','请问 + Question','[{"zh": "请问，厕所在哪儿？", "pinyin": "Qǐngwèn, cèsuǒ zài nǎr?", "mn": "Уучлаарай, ариун цэврийн өрөө хаана вэ?"}, {"zh": "请问您贵姓？", "pinyin": "Qǐngwèn nín guìxìng?", "mn": "Таны овог хэн бэ?"}]',1,30,1);
INSERT INTO grammar_exercises (id,grammar_lesson_id,exercise_type,question_zh,correct_answer,options,explanation_mn,order_num) VALUES
