(78,26,'true_false','那是学校。= Тэр нь сургууль.','true','[]','那=тэр зүйлийг заана',3),
(79,27,'fill_blank','你有___个苹果？','几','["几","多少","多","很"]','Хүн, жимс тоолохдоо 几',1),
(80,27,'choose_correct','Хэдэн цаг вэ? →','几点？','["几点？","几月？","几年？"]','Цаг асуух 点',2),
(81,27,'true_false','几个人 = Хэдэн хүн','true','[]','',3),
(82,28,'fill_blank','我们走___。','吧','["吧","吗","呢","的"]','Саналын 吧',1),
(83,28,'reorder','吧/坐/你 →','你坐吧。','[]','хүн + үйл + 吧',2),
(84,28,'true_false','我们走吧 = Явцгаая','true','[]','',3),
(85,29,'fill_blank','我___妈妈在家。','和','["和","是","的","在"]','Хоёр хүн холбох 和',1),
(86,29,'translate','Би ба ээж гэртээ →','我和妈妈在家。','[]','',2),
(87,29,'choose_correct','цай ба кофе →','茶和咖啡','["茶和咖啡","茶或咖啡","茶是咖啡"]','',3),
(88,30,'fill_blank','___，厕所在哪儿？','请问','["请问","请坐","谢谢","对不起"]','Асуултын өмнө 请问',1),
(89,30,'choose_correct','Эелдэгээр асуухын өмнө →','请问','["请问","再见","好吗","是吗"]','',2),
